import { useEffect, useMemo, useState } from "react";
import ConfirmDialog from "./ConfirmDialog";

const getFileBadge = (contentType = "", originalFilename = "") => {
  const lowerName = originalFilename.toLowerCase();

  if (contentType.includes("pdf") || lowerName.endsWith(".pdf")) {
    return "PDF";
  }

  if (contentType.startsWith("image/")) {
    return "IMG";
  }

  if (contentType.includes("word") || lowerName.endsWith(".doc") || lowerName.endsWith(".docx")) {
    return "DOC";
  }

  if (contentType.includes("json") || lowerName.endsWith(".json")) {
    return "JSON";
  }

  if (contentType.includes("csv") || lowerName.endsWith(".csv")) {
    return "CSV";
  }

  return "FILE";
};

function TrashPage({
  trashService,
  formatDateTime,
  onRestoreSuccess,
  onDeleteSuccess,
  onError
}) {
  const [trashFiles, setTrashFiles] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [pageError, setPageError] = useState("");
  const [searchValue, setSearchValue] = useState("");
  const [sortBy, setSortBy] = useState("expiry");
  const [pendingAction, setPendingAction] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    let isMounted = true;

    const loadTrash = async () => {
      setIsLoading(true);

      try {
        const files = await trashService.fetchTrashFiles();

        if (isMounted) {
          setPageError("");
          setTrashFiles(files);
        }
      } catch (error) {
        if (isMounted) {
          setPageError(error.message);
          onError(error.message);
        }
      } finally {
        if (isMounted) {
          setIsLoading(false);
        }
      }
    };

    loadTrash();

    return () => {
      isMounted = false;
    };
  }, [onError, trashService]);

  const visibleFiles = useMemo(() => {
    const normalizedQuery = searchValue.trim().toLowerCase();
    const filtered = trashFiles.filter((file) => {
      if (!normalizedQuery) {
        return true;
      }

      return [file.displayName, file.originalFilename, file.contentType]
        .join(" ")
        .toLowerCase()
        .includes(normalizedQuery);
    });

    return filtered.sort((left, right) => {
      if (sortBy === "deleted") {
        return new Date(right.deletedAt || 0) - new Date(left.deletedAt || 0);
      }

      if (sortBy === "name") {
        return left.displayName.localeCompare(right.displayName);
      }

      return (left.daysRemaining ?? 999) - (right.daysRemaining ?? 999);
    });
  }, [searchValue, sortBy, trashFiles]);

  const handleRestore = async (file) => {
    setPendingAction({
      type: "restore",
      file
    });
  };

  const handlePermanentDelete = async (file) => {
    setPendingAction({
      type: "delete",
      file
    });
  };

  const submitPendingAction = async () => {
    if (!pendingAction?.file) {
      return;
    }

    const targetFile = pendingAction.file;
    const previousFiles = trashFiles;

    setIsSubmitting(true);

    setTrashFiles((current) => current.filter((file) => file.fileId !== targetFile.fileId));

    try {
      if (pendingAction.type === "restore") {
        await trashService.restoreFile(targetFile.fileId);
        setPageError("");
        onRestoreSuccess(`${targetFile.displayName} restored successfully.`);
      } else {
        await trashService.permanentlyDeleteFile(targetFile.fileId);
        setPageError("");
        onDeleteSuccess(`${targetFile.displayName} deleted permanently.`);
      }
    } catch (error) {
      setTrashFiles(previousFiles);
      onError(error.message);
    } finally {
      setPendingAction(null);
      setIsSubmitting(false);
    }
  };

  const closeDialog = () => {
    setPendingAction(null);
    setIsSubmitting(false);
  };

  const restoreAll = async () => {
    for (const file of visibleFiles) {
      try {
        await trashService.restoreFile(file.fileId);
      } catch (error) {
        onError(error.message);
        return;
      }
    }

    setTrashFiles((current) => current.filter((file) => !visibleFiles.some((item) => item.fileId === file.fileId)));
    onRestoreSuccess(`${visibleFiles.length} file(s) restored successfully.`);
  };

  return (
    <section className="content-section trash-shell">
      <div className="section-heading section-heading-inline">
        <div>
          <p className="eyebrow">Trash</p>
          <h2 className="section-title">Recovered files stay here for 15 days.</h2>
          <p className="section-copy">
            Restore anything before it expires, or permanently delete it right away.
          </p>
        </div>
        <div className="button-row">
          <button
            type="button"
            className="secondary-button"
            disabled={!visibleFiles.length || isLoading}
            onClick={restoreAll}
          >
            Restore All
          </button>
        </div>
      </div>

      <section className="panel trash-toolbar">
        <div className="trash-toolbar-grid">
          <input
            type="text"
            className="text-input"
            placeholder="Search inside trash"
            value={searchValue}
            onChange={(event) => setSearchValue(event.target.value)}
          />
          <select
            className="text-input"
            value={sortBy}
            onChange={(event) => setSortBy(event.target.value)}
          >
            <option value="expiry">Sort by expiry</option>
            <option value="deleted">Sort by deleted date</option>
            <option value="name">Sort by file name</option>
          </select>
        </div>
      </section>

      {isLoading ? (
        <section className="panel empty-state trash-empty-state">Loading trash files...</section>
      ) : pageError && trashFiles.length === 0 ? (
        <section className="panel empty-state trash-empty-state trash-error-state">
          <strong>Trash is unavailable</strong>
          <p>{pageError}</p>
        </section>
      ) : visibleFiles.length === 0 ? (
        <section className="panel empty-state trash-empty-state">
          <strong>Trash is empty</strong>
          <p>No deleted files are waiting for review right now.</p>
        </section>
      ) : (
        <section className="trash-grid">
          {visibleFiles.map((file) => (
            <article className="trash-card" key={file.fileId}>
              <div className="trash-card-top">
                <div className="trash-icon">{getFileBadge(file.contentType, file.originalFilename)}</div>
                <div className="trash-card-copy">
                  <h3>{file.displayName}</h3>
                  <p>Original file: {file.originalFilename}</p>
                </div>
              </div>

              <div className="trash-meta-grid">
                <div className="file-meta-card">
                  <span>Deleted</span>
                  <strong>{file.deletedAt ? formatDateTime(file.deletedAt) : "Recently"}</strong>
                </div>
                <div className="file-meta-card">
                  <span>Expires</span>
                  <strong>
                    {file.daysRemaining === null ? "Unknown" : `In ${file.daysRemaining} day${file.daysRemaining === 1 ? "" : "s"}`}
                  </strong>
                </div>
                <div className="file-meta-card">
                  <span>Type</span>
                  <strong>{file.contentType || "unknown"}</strong>
                </div>
              </div>

              <div className="button-row trash-actions">
                <button
                  type="button"
                  className="primary-button"
                  onClick={() => handleRestore(file)}
                >
                  Restore
                </button>
                <button
                  type="button"
                  className="danger-button"
                  onClick={() => handlePermanentDelete(file)}
                >
                  Delete Permanently
                </button>
              </div>
            </article>
          ))}
        </section>
      )}

      <ConfirmDialog
        isOpen={Boolean(pendingAction)}
        title={
          pendingAction?.type === "restore"
            ? "Restore this file?"
            : "Delete this file permanently?"
        }
        description={
          pendingAction?.type === "restore"
            ? `Restore ${pendingAction?.file?.displayName || "this file"} back to your main workspace.`
            : `Permanently remove ${pendingAction?.file?.displayName || "this file"} from trash and storage.`
        }
        confirmLabel={pendingAction?.type === "restore" ? "Restore File" : "Delete Permanently"}
        tone={pendingAction?.type === "restore" ? "default" : "danger"}
        isSubmitting={isSubmitting}
        onCancel={closeDialog}
        onConfirm={submitPendingAction}
      />
    </section>
  );
}

export default TrashPage;
